const rechargeTypes = Object.values(CONFIG.SWADE.CONST.CHARGE_RECHARGE_TYPE).slice(1);;
const optionsHTML = rechargeTypes
  .map((val) => `<option value="${val}">${game.i18n.localize(CONFIG.SWADE.chargeRechargeTypes[val])}</option>`)
  .join("\n");

const content = `
  <form>
    <div class="form-group">
      <label for="rechargeType">Recharge Type:</label>
      <select id="rechargeType" name="rechargeType">
        ${optionsHTML}
      </select>
    </div>
  </form>
`;

let selected;
const recharge = await foundry.applications.api.DialogV2.confirm({
  window: { title: "Recharge Items" },
  content: content,
  yes: {
    label: "Recharge",
    icon: "fas fa-rotate",
    callback:(event, button, dialog) => {
    selected = dialog.element.querySelector('[name="rechargeType"]').value;
    }
  },
  no: {
    label: "Cancel"
  }
});

if (recharge) {
  for (const token of game.foundryDumpingGround.getSelected()) {
    for (const item of token.actor.items) {
      item.rechargeAllChargesOfType(selected);
    }
  }
}
